INSERT INTO `monthly_report` (`id`, `user_id`, `report_year`, `report_month`, `total_expense`, `prev_expense`, `diff_ratio`, `success_weeks`, `total_weeks`, `top_category`, `category_json`, `extra_json`, `one_liner`, `mood`, `category_comment`, `advice`, `story`, `user_message`, `gulbi_reply`, `replied_at`, `generated_at`) VALUES (1,1,2026,5,620000.00,293000.00,111.60,1,5,'의류','[{\"categoryId\":5,\"categoryName\":\"의류\",\"amount\":210000.00,\"ratio\":33.87,\"prevAmount\":95000.00,\"prevRatio\":32.42,\"diffAmount\":115000.00},{\"categoryId\":7,\"categoryName\":\"문화생활\",\"amount\":140000.00,\"ratio\":22.58,\"prevAmount\":48000.00,\"prevRatio\":16.38,\"diffAmount\":92000.00},{\"categoryId\":4,\"categoryName\":\"식비\",\"amount\":127000.00,\"ratio\":20.48,\"prevAmount\":0,\"prevRatio\":0,\"diffAmount\":127000.00},{\"categoryId\":8,\"categoryName\":\"의료비\",\"amount\":80000.00,\"ratio\":12.90,\"prevAmount\":60000.00,\"prevRatio\":20.48,\"diffAmount\":20000.00},{\"categoryId\":null,\"categoryName\":\"기타\",\"amount\":63000.00,\"ratio\":10.16,\"prevAmount\":39000.00,\"prevRatio\":13.31,\"diffAmount\":24000.00,\"members\":[{\"categoryId\":6,\"categoryName\":\"교통비\",\"amount\":63000.00,\"ratio\":10.16}]},{\"categoryId\":6,\"categoryName\":\"교통비\",\"amount\":0,\"ratio\":0,\"prevAmount\":51000.00,\"prevRatio\":17.41,\"diffAmount\":-51000.00}]','{\"dailyAvg\":20000,\"noSpendDays\":25,\"biggestDay\":{\"date\":\"2026-05-15\",\"amount\":210000.00},\"savedMost\":{\"name\":\"교통비\",\"diff\":-51000.00},\"spentMost\":{\"name\":\"식비\",\"diff\":127000.00},\"weeks\":[{\"label\":\"1주차\",\"ratio\":0.00,\"pass\":true},{\"label\":\"2주차\",\"ratio\":135.00,\"pass\":false},{\"label\":\"3주차\",\"ratio\":210.00,\"pass\":false},{\"label\":\"4주차\",\"ratio\":195.00,\"pass\":false},{\"label\":\"5주차\",\"ratio\":114.29,\"pass\":false}]}','이번 달은 지출이 크게 불어나 마음이 좀 쓰리다.','sad','의류랑 문화생활이 전월보다 많이 늘었네. 꼭 필요한 것부터 먼저 챙기고, 사고 싶은 건 하루만 더 미뤄봐.','의류·문화생활은 미리 한도 정해두고, 식비는 장보기부터 적게 나눠 써봐. 한 번만 더 묶으면 새는 돈 줄어든다.','이번 달 총지출은 620,000원으로 전월 293,000원보다 많이 늘었구나. 가장 많이 쓴 건 의류였고, 그다음으로 문화생활과 식비가 뒤를 이었어. 교통비는 0원으로 잘 막아냈지만, 주간 예산은 1주만 성공해서 살림살이가 좀 흔들렸네. 그래도 이렇게 흐름을 딱 짚어본 것만으로도 반은 이긴 거다. 다음 달엔 덜 아프게, 더 단단하게 가보자. 너는 충분히 다시 바로잡을 수 있어.',NULL,NULL,NULL,'2026-06-25 20:08:25');
INSERT INTO `monthly_report` (`id`, `user_id`, `report_year`, `report_month`, `total_expense`, `prev_expense`, `diff_ratio`, `success_weeks`, `total_weeks`, `top_category`, `category_json`, `extra_json`, `one_liner`, `mood`, `category_comment`, `advice`, `story`, `user_message`, `gulbi_reply`, `replied_at`, `generated_at`) VALUES (2,4,2026,5,0.00,0.00,NULL,0,0,NULL,'[]','{\"dailyAvg\":0,\"noSpendDays\":31,\"biggestDay\":null,\"savedMost\":null,\"spentMost\":null,\"weeks\":[]}','한 푼도 안 새고 지킨 달, 아주 기특해!','happy','늘어난 카테고리는 없네. 새는 돈 없이 딱 지킨 살림, 참 알뜰했어.','이번 달은 지출이 없었구나, 참 기특해. 다음 달도 꼭 필요한 것만 먼저 적어두고 살펴봐.','이번 달은 총 지출이 0원이라 살림이 아주 단단했어. 전월 지출도 0원이라 비교할 흐름은 없지만, 새는 돈 없이 버틴 것만으로도 참 대견하지. 가장 많이 쓴 항목도 없고, 주간 예산도 0주 / 0주로 깔끔하게 마무리됐네. 이렇게 빈틈 없이 지킨 한 달은 말 그대로 절약의 기본을 잘 세운 달이야. 굴비는 이런 꾸준함이 제일 좋더라. 다음 달도 이 기운 이어가자.',NULL,NULL,NULL,'2026-06-25 20:20:31');
